  ('dietitian-moex-01273', 'dietitian', 'dietitian-moex-110-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '脂肪酸從細胞質進入粒線體進行beta-氧化作用，須先轉換成醯基脂肪酸-輔酶A（fattyacyl-CoA）， 再透過那一個轉移酶與肉鹼共價結合進入粒線體內？', '["CarnitineacyltransferaseI", "CarnitineacyltransferaseII", "Acyl-CoA：cholesterolacyltransferase（ACAT）", "Lecithin：cholesterolacyltransferase（LCAT）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:54+00:00", "source_pdf_sha1": "4682e1f98de9", "answer_pdf_sha1": "0a3c7097368a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
